INSERT INTO `heritage_project` (`id`, `name`, `category_id`, `level`, `description`, `region`, `image_url`, `status`, `created_at`, `updated_at`) VALUES
(1, '南通蓝印花布印染技艺', 13, '国家级', '蓝印花布是中国传统的手工印花染色技术，以蓝白两色为主色调，图案朴素优美，具有浓郁的民间艺术风格。', '江苏南通', NULL, 1, '2025-01-02 00:00:00', '2025-01-02 00:00:00'),
(2, '景德镇手工制瓷技艺', 10, '国家级', '景德镇传统手工制瓷技艺涵盖了拉坯、利坯、画坯、施釉和烧窑等72道工序，是中华陶瓷文化的瑰宝。', '江西景德镇', NULL, 1, '2025-01-02 00:00:00', '2025-01-02 00:00:00'),
(3, '苏州刺绣', 9, '国家级', '苏绣是中国四大名绣之一，以精细雅洁著称，题材广泛，技法独特，色彩清雅。', '江苏苏州', NULL, 1, '2025-01-02 00:00:00', '2025-01-02 00:00:00'),
(4, '东阳木雕', 11, '国家级', '东阳木雕因产于浙江东阳而得名，以平面浮雕为主，题材多为花鸟山水、民间故事。', '浙江东阳', NULL, 1, '2025-01-02 00:00:00', '2025-01-02 00:00:00'),
(5, '福州脱胎漆器髹饰技艺', 12, '国家级', '福州脱胎漆器与北京景泰蓝、江西景德镇瓷器并誉为中国传统工艺"三宝"。', '福建福州', NULL, 1, '2025-01-02 00:00:00', '2025-01-02 00:00:00'),
(6, '中国剪纸', 8, '国家级', '中国剪纸是世界级非物质文化遗产，用剪刀或刻刀在纸上剪刻花纹，用于装点生活或配合民俗活动。', '全国', NULL, 1, '2025-01-02 00:00:00', '2025-01-02 00:00:00'),
(7, '豫剧', 5, '国家级', '豫剧是中国五大戏曲剧种之一，起源于河南，以唱腔铿锵大气、抑扬有度著称。', '河南', NULL, 1, '2025-01-03 00:00:00', '2025-01-03 00:00:00'),
(8, '竹编工艺', 14, '省级', '利用竹子的韧性和弹性，通过编、织、穿、绕等手法制作各种生活用品和工艺品。', '四川', NULL, 1, '2025-01-03 00:00:00', '2025-01-03 00:00:00'),
(9, '汝瓷烧制技艺', 10, '省级', '汝瓷以温润的天青色闻名于世，烧制工艺复杂，需精确控制窑温和还原气氛。', '河南汝州', NULL, 1, '2025-01-04 00:00:00', '2025-01-04 00:00:00'),
(10, '朱仙镇木版年画', 16, '国家级', '朱仙镇木版年画起源于北宋，是中国四大年画之一，以线条粗犷、色彩鲜艳著称。', '河南开封', NULL, 1, '2025-01-04 00:00:00', '2025-01-04 00:00:00'),
(11, '蜀绣', 9, '国家级', '蜀绣又名川绣，与苏绣、湘绣、粤绣齐名，以针法细腻、色彩明丽闻名。', '四川成都', NULL, 1, '2025-01-05 00:00:00', '2025-01-05 00:00:00'),
(12, '扎染技艺', 13, '省级', '大理白族扎染技艺是云南传统手工印染技术，以板蓝根为染料，图案独具民族特色。', '云南大理', NULL, 1, '2025-01-05 00:00:00', '2025-01-05 00:00:00');
INSERT INTO `master_profile` (`id`, `user_id`, `title`, `heritage_project_id`, `skill_category_id`, `career_years`, `career_history`, `specialties`, `representative_works`, `bio`, `honor`, `audit_status`, `created_at`, `updated_at`) VALUES
(1, 2, '省级非遗传承人', 1, 13, 35, '1990年随祖母学习蓝印花布印染技艺，1995年独立完成第一件作品，2000年被认定为市级非遗传承人，2010年获省级非遗传承人称号。多次赴海外进行文化交流。', '蓝印花布印染、图案设计、染料配制', '["蓝印花布百福图","四季花卉蓝印长卷","龙凤呈祥蓝印挂毯"]', '张明远，男，1975年生于江苏南通，师承祖母学习蓝印花布印染技艺，从艺35年。致力于传统蓝印花布技艺的传承与创新，在保持传统工艺精髓的基础上融入现代设计元素。', '省级非遗代表性传承人、全国工艺美术优秀创作奖', 1, '2025-01-05 09:30:00', '2025-01-05 09:30:00'),
(2, 3, '市级非遗传承人', 3, 9, 28, '1997年进入苏州刺绣研究所学习，师从著名刺绣大师。2005年成立个人刺绣工作室，2012年被评为市级非遗传承人。作品多次在国家级展览中获奖。', '苏绣、双面绣、乱针绣', '["百鸟朝凤双面绣屏风","牡丹图团扇","山水长卷刺绣"]', '李秀芳，女，1980年生于江苏苏州，自幼跟随母亲学习刺绣，后入苏州刺绣研究所深造。从艺28年，擅长双面绣和乱针绣技法，作品融合传统与现代审美。', '市级非遗代表性传承人、江苏省工艺美术名人', 1, '2025-01-08 10:00:00', '2025-01-08 10:00:00'),
(3, 4, '省级非遗传承人', 2, 10, 40, '1985年进入景德镇陶瓷厂学徒，1993年创办个人陶瓷工作室，专注于传统青花瓷和粉彩瓷制作。2008年被授予省级非遗传承人称号。', '青花瓷、粉彩瓷、拉坯、画坯', '["青花山水大瓶","粉彩花鸟茶具套装","仿古青花瓷盘"]', '王德厚，男，1970年生于江西景德镇，陶瓷世家第四代传人。从艺40年，精通景德镇传统72道制瓷工序，尤擅青花绘制与粉彩技法。', '省级非遗代表性传承人、中国陶瓷艺术大师', 1, '2025-01-12 14:00:00', '2025-01-12 14:00:00');
INSERT INTO `master_apprentice_relation` (`id`, `master_id`, `apprentice_id`, `heritage_project_id`, `apply_reason`, `status`, `apply_time`, `approve_time`, `created_at`, `updated_at`) VALUES
(1, 2, 5, 1, '从小对蓝印花布印染技艺有浓厚兴趣，希望跟随张师傅系统学习传统印染工艺，传承这门珍贵的非遗技艺。', 1, '2025-02-01 10:00:00', '2025-02-03 15:00:00', '2025-02-01 10:00:00', '2025-02-03 15:00:00'),
(2, 2, 6, 1, '大学期间学习过染织设计专业，对传统蓝印花布工艺深感敬佩，希望在张师傅指导下深入学习传统技艺。', 1, '2025-02-05 09:00:00', '2025-02-07 11:00:00', '2025-02-05 09:00:00', '2025-02-07 11:00:00'),
(3, 3, 7, 3, '自幼喜爱刺绣，有一定的基础功底。希望跟随李师傅学习苏绣精湛技法，将这门传统艺术发扬光大。', 1, '2025-02-10 14:00:00', '2025-02-12 10:00:00', '2025-02-10 14:00:00', '2025-02-12 10:00:00'),
(4, 3, 8, 3, '美术专业毕业，对刺绣艺术有独特的理解和追求，希望能在李师傅门下深造，提升技艺水平。', 1, '2025-02-15 11:00:00', '2025-02-17 09:00:00', '2025-02-15 11:00:00', '2025-02-17 09:00:00'),
(5, 4, 9, 2, '景德镇陶瓷大学在读研究生，对传统制瓷技艺有深入的理论研究，渴望在王师傅指导下进行实践。', 1, '2025-02-20 10:00:00', '2025-02-22 14:00:00', '2025-02-20 10:00:00', '2025-02-22 14:00:00'),
(6, 4, 10, 2, '来自陶瓷之乡，从小耳濡目染，对制瓷有天然的热爱和悟性，希望跟随王师傅系统学习制瓷全工序。', 1, '2025-02-25 09:30:00', '2025-02-27 16:00:00', '2025-02-25 09:30:00', '2025-02-27 16:00:00'),
(7, 2, 11, 1, '对非遗文化保护有强烈使命感，希望通过拜师学习蓝印花布技艺，为非遗数字化保护贡献力量。', 0, '2025-03-10 08:00:00', NULL, '2025-03-10 08:00:00', '2025-03-10 08:00:00'),
(8, 3, 12, 3, '从小对针线活有天赋，立志成为新一代苏绣传承人，恳请李师傅收徒指导。', 0, '2025-03-12 10:00:00', NULL, '2025-03-12 10:00:00', '2025-03-12 10:00:00'),
(9, 2, 8, 1, '曾对蓝印花布产生兴趣但后来选择了刺绣方向，此前的申请已被拒绝。', 2, '2025-01-20 09:00:00', '2025-01-22 11:00:00', '2025-01-20 09:00:00', '2025-01-22 11:00:00');
INSERT INTO `teaching_task` (`id`, `title`, `description`, `master_id`, `heritage_project_id`, `skill_category_id`, `deadline`, `status`, `created_at`, `updated_at`) VALUES
(1, '蓝印花布基础图案刻版学习', '学习蓝印花布传统图案的刻版技术，包括花卉、动物、几何等常见图案的构图方法和刻版要领。要求每位徒弟完成至少3种不同风格的图案刻版练习。', 2, 1, 13, '2025-04-01 23:59:59', 1, '2025-02-10 08:00:00', '2025-02-10 08:00:00'),
(2, '传统染料配制与色彩控制', '学习使用天然植物靛蓝染料的配制方法，掌握不同浓度下的色彩深浅变化规律。要求记录完整的实验数据。', 2, 1, 13, '2025-04-15 23:59:59', 0, '2025-02-20 10:00:00', '2025-02-20 10:00:00'),
(3, '苏绣基础针法练习', '系统学习平绣、齐针、套针、施针等基础针法，每种针法完成一个10cm*10cm的练习作品，并记录学习心得。', 3, 3, 9, '2025-03-30 23:59:59', 1, '2025-02-15 09:00:00', '2025-02-15 09:00:00'),
(4, '双面绣入门技法', '在掌握基础针法后，学习双面绣的起针、转针、藏针等核心技法，完成一幅简单的双面绣小品（花卉主题）。', 3, 3, 9, '2025-05-01 23:59:59', 0, '2025-03-01 14:00:00', '2025-03-01 14:00:00'),
(5, '拉坯基本功训练', '学习景德镇传统拉坯技艺，从揉泥、定中心、开孔、拉筒到成型，每人完成碗、杯、瓶三种基本器型各5件。', 4, 2, 10, '2025-04-20 23:59:59', 1, '2025-03-01 08:00:00', '2025-03-01 08:00:00'),
(6, '青花绘制技法学习', '学习传统青花瓷的绘制技法，包括分水、勾线、染色等。要求在素坯上完成一组传统花鸟纹样的绘制。', 4, 2, 10, '2025-05-15 23:59:59', 0, '2025-03-15 10:00:00', '2025-03-15 10:00:00'),
(7, '蓝印花布成品制作', '综合运用刻版、调浆、刮浆、染色、刮白等完整工序，独立完成一件蓝印花布桌布的制作。', 2, 1, 13, '2025-06-01 23:59:59', 0, '2025-03-20 09:00:00', '2025-03-20 09:00:00'),
(8, '乱针绣创新实践', '在传统乱针绣基础上，融入个人创意，以风景或人物为主题，完成一幅不小于30cm*40cm的创新绣品。', 3, 3, 9, '2025-06-15 23:59:59', 0, '2025-03-25 11:00:00', '2025-03-25 11:00:00'),
(9, '窑炉温度控制实践', '学习景德镇传统柴窑烧制的温度控制技术，了解不同温度段对瓷器釉面的影响，记录烧窑全过程数据。', 4, 2, 10, '2025-06-30 23:59:59', 0, '2025-04-01 08:00:00', '2025-04-01 08:00:00'),
(10, '非遗文化调研报告', '走访当地非遗传承人，收集口述历史资料，撰写一篇不少于3000字的非遗文化调研报告。', 2, 1, 13, '2025-05-01 23:59:59', 0, '2025-03-10 09:00:00', '2025-03-10 09:00:00');
INSERT INTO `task_submission` (`id`, `task_id`, `apprentice_id`, `content`, `file_url`, `status`, `master_comment`, `score`, `submit_time`, `review_time`, `created_at`, `updated_at`) VALUES
(1, 1, 5, '完成了牡丹花、蝴蝶和万字纹三种图案的刻版练习。在刻版过程中体会到了力道控制的重要性，线条流畅度还需要多加练习。', '/uploads/submissions/sub_001.jpg', 2, '刻版基本功扎实，线条流畅度需要加强，牡丹花的花瓣层次感可以再丰富一些。继续保持学习热情！', 85, '2025-03-01 16:00:00', '2025-03-03 10:00:00', '2025-03-01 16:00:00', '2025-03-03 10:00:00'),
(2, 1, 6, '完成了梅花、喜鹊和回纹三种图案。梅花的枝干走势比较满意，喜鹊的羽毛细节处理还需改进。', '/uploads/submissions/sub_002.jpg', 2, '构图大气，对传统纹样理解到位。喜鹊的羽毛建议参考宋代花鸟画的处理手法。整体进步明显！', 88, '2025-03-05 14:30:00', '2025-03-07 09:00:00', '2025-03-05 14:30:00', '2025-03-07 09:00:00'),
(3, 3, 7, '完成了平绣和齐针两种针法的练习作品。平绣比较顺利，齐针的针脚均匀度还需加强。', '/uploads/submissions/sub_003.jpg', 2, '平绣掌握得不错，线条整齐。齐针练习中注意保持每一针的间距一致，这需要大量练习，不要着急。', 82, '2025-03-10 15:00:00', '2025-03-12 11:00:00', '2025-03-10 15:00:00', '2025-03-12 11:00:00'),
(4, 3, 8, '四种基础针法的练习作品全部完成。个人觉得施针最难，容易出现针脚不规则的情况。', '/uploads/submissions/sub_004.jpg', 2, '进度很快，四种针法全部完成值得表扬！施针确实是难点，建议用细线在薄布上反复练习，会有明显进步。', 90, '2025-03-08 10:00:00', '2025-03-10 14:00:00', '2025-03-08 10:00:00', '2025-03-10 14:00:00'),
(5, 5, 9, '完成了5个碗和5个杯的拉坯练习。拉坯时泥料的含水量控制是最大的难点，有几件作品因为泥太软而变形。', '/uploads/submissions/sub_005.jpg', 2, '拉坯功底不错，器型基本规整。注意揉泥时要把气泡排尽，含水量要根据季节调整。瓶的练习要加快进度。', 80, '2025-03-20 16:00:00', '2025-03-22 10:00:00', '2025-03-20 16:00:00', '2025-03-22 10:00:00'),
(6, 5, 10, '三种器型各完成了5件。碗和杯的成功率较高，瓶的口部处理需要加强，容易出现不圆的情况。', '/uploads/submissions/sub_006.jpg', 1, NULL, NULL, '2025-03-25 11:00:00', NULL, '2025-03-25 11:00:00', '2025-03-25 11:00:00'),
(7, 2, 5, '记录了不同浓度靛蓝染料的配制过程和上色效果对比。发现温度对染色效果有显著影响。', '/uploads/submissions/sub_007.pdf', 0, NULL, NULL, '2025-04-01 10:00:00', NULL, '2025-04-01 10:00:00', '2025-04-01 10:00:00'),
(8, 10, 5, '走访了南通地区3位蓝印花布传承人，收集了大量一手口述资料，完成了调研报告初稿。', '/uploads/submissions/sub_008.pdf', 0, NULL, NULL, '2025-04-10 14:00:00', NULL, '2025-04-10 14:00:00', '2025-04-10 14:00:00');
INSERT INTO `learning_material` (`id`, `title`, `description`, `file_url`, `file_type`, `file_size`, `task_id`, `uploader_id`, `heritage_project_id`, `created_at`, `updated_at`) VALUES
(1, '蓝印花布传统图案集', '收录了100多种蓝印花布经典图案，包含花卉、动物、人物、几何纹样等分类。', '/uploads/materials/mat_001.pdf', 'PDF', 15728640, 1, 2, 1, '2025-02-10 08:30:00', '2025-02-10 08:30:00'),
(2, '刻版工具使用指南', '详细介绍了刻版刀、油纸板、浆料等工具的使用方法和保养技巧。', '/uploads/materials/mat_002.pdf', 'PDF', 5242880, 1, 2, 1, '2025-02-10 08:45:00', '2025-02-10 08:45:00'),
(3, '天然靛蓝染料配制手册', '记录了传统靛蓝染料的配制方法、不同浓度的色彩效果、温度与时间的控制要领。', '/uploads/materials/mat_003.pdf', 'PDF', 8388608, 2, 2, 1, '2025-02-20 10:30:00', '2025-02-20 10:30:00'),
(4, '苏绣基础针法教学视频', '李师傅亲自示范平绣、齐针、套针、施针四种基础针法的操作要领。', '/uploads/materials/mat_004.mp4', 'VIDEO', 524288000, 3, 3, 3, '2025-02-15 09:30:00', '2025-02-15 09:30:00'),
(5, '苏绣配色指南', '介绍苏绣传统配色方案和丝线选择方法，含50组经典配色组合。', '/uploads/materials/mat_005.pdf', 'PDF', 10485760, 3, 3, 3, '2025-02-15 10:00:00', '2025-02-15 10:00:00'),
(6, '双面绣技法详解', '详细讲解双面绣的核心技法：起针不留痕、转针无接头、藏针无断线。', '/uploads/materials/mat_006.pdf', 'PDF', 12582912, 4, 3, 3, '2025-03-01 14:30:00', '2025-03-01 14:30:00'),
(7, '景德镇传统拉坯教程', '王师傅录制的拉坯全流程教学视频，从揉泥到成型的完整演示。', '/uploads/materials/mat_007.mp4', 'VIDEO', 734003200, 5, 4, 2, '2025-03-01 08:30:00', '2025-03-01 08:30:00'),
(8, '青花瓷绘制技法图解', '包含分水、勾线、染色三大技法的图文详解，附历代经典青花纹样赏析。', '/uploads/materials/mat_008.pdf', 'PDF', 20971520, 6, 4, 2, '2025-03-15 10:30:00', '2025-03-15 10:30:00'),
(9, '非遗项目申报指南', '整理了国家级、省级非遗项目的申报流程、条件与注意事项。', '/uploads/materials/mat_009.pdf', 'PDF', 3145728, NULL, 2, 1, '2025-02-01 09:00:00', '2025-02-01 09:00:00'),
(10, '传统手工艺品鉴赏教材', '系统介绍了中国十大传统手工艺的发展历程、工艺特点与鉴赏方法。', '/uploads/materials/mat_010.pdf', 'PDF', 41943040, NULL, 4, 2, '2025-01-20 10:00:00', '2025-01-20 10:00:00');
INSERT INTO `artwork` (`id`, `title`, `description`, `apprentice_id`, `master_id`, `heritage_project_id`, `skill_category_id`, `image_urls`, `video_url`, `status`, `created_at`, `updated_at`) VALUES
(1, '春归蓝印花布围巾', '以春天回归为主题，采用传统蓝印花布工艺制作的围巾。图案以燕子归巢和桃花盛开为主要元素，寓意春回大地、万物复苏。', 5, 2, 1, 13, '["https://example.com/artworks/art_001_1.jpg","https://example.com/artworks/art_001_2.jpg"]', NULL, 2, '2025-03-15 14:00:00', '2025-03-18 10:00:00'),
(2, '蓝印花布茶席套装', '运用传统蓝印花布技艺制作的茶席套装，包含茶垫、杯垫和壶承三件套。图案选用莲花与荷叶，体现茶道清雅之韵。', 6, 2, 1, 13, '["https://example.com/artworks/art_002_1.jpg"]', NULL, 2, '2025-03-20 10:00:00', '2025-03-22 15:00:00'),
(3, '牡丹蝴蝶苏绣团扇', '以传统工笔画风格绣制的牡丹蝴蝶团扇，采用平绣与套针相结合的技法，色彩层次丰富。', 7, 3, 3, 9, '["https://example.com/artworks/art_003_1.jpg","https://example.com/artworks/art_003_2.jpg"]', NULL, 2, '2025-03-25 11:00:00', '2025-03-28 09:00:00'),
(4, '锦鲤戏水双面绣小品', '初次尝试双面绣技法的习作，以锦鲤戏水为主题。正面为全景，背面为局部特写，虽有不足但已初具双面绣神韵。', 8, 3, 3, 9, '["https://example.com/artworks/art_004_1.jpg"]', NULL, 1, '2025-03-30 14:00:00', '2025-03-30 14:00:00'),
(5, '青花瓷茶杯组', '在王师傅指导下完成的第一组青花瓷茶杯，采用传统缠枝莲纹装饰，釉面温润，花色清雅。', 9, 4, 2, 10, '["https://example.com/artworks/art_005_1.jpg","https://example.com/artworks/art_005_2.jpg"]', NULL, 2, '2025-04-01 10:00:00', '2025-04-03 14:00:00'),
(6, '粉彩花鸟小瓶', '练习粉彩技法的习作，以喜鹊登梅为题材，釉上彩绘制而成。色彩搭配还需改进。', 10, 4, 2, 10, '["https://example.com/artworks/art_006_1.jpg"]', NULL, 1, '2025-04-05 15:00:00', '2025-04-05 15:00:00'),
(7, '蓝印花布手提袋', '将传统蓝印花布与现代手提袋设计结合，图案采用传统万字纹和祥云纹，实用与美观兼备。', 5, 2, 1, 13, '["https://example.com/artworks/art_007_1.jpg"]', NULL, 1, '2025-04-10 09:00:00', '2025-04-10 09:00:00'),
(8, '梅花三弄苏绣挂画', '以梅花为主题的苏绣挂画，运用了乱针绣技法表现梅花的枝干质感，是一次大胆的技法创新尝试。', 7, 3, 3, 9, '["https://example.com/artworks/art_008_1.jpg","https://example.com/artworks/art_008_2.jpg"]', NULL, 0, '2025-04-12 16:00:00', '2025-04-12 16:00:00'),
(9, '仿古青花瓷盘', '参考元代青花瓷经典纹样，在30cm瓷盘上绘制的仿古青花作品。', 9, 4, 2, 10, '["https://example.com/artworks/art_009_1.jpg"]', NULL, 1, '2025-04-15 10:00:00', '2025-04-15 10:00:00'),
(10, '蓝印花布抱枕', '以鱼戏莲为主题的蓝印花布抱枕，表达年年有余的美好寓意。', 6, 2, 1, 13, '["https://example.com/artworks/art_010_1.jpg"]', NULL, 0, '2025-04-18 11:00:00', '2025-04-18 11:00:00');
INSERT INTO `artwork_review` (`id`, `artwork_id`, `reviewer_id`, `content`, `score`, `created_at`, `updated_at`) VALUES
(1, 1, 2, '整体构图合理，燕子的形态生动，桃花的色彩渲染自然。在刻版线条的粗细变化上可以更加大胆，让图案更有层次感。作为初期作品已经很不错了，继续加油！', 88, '2025-03-18 10:00:00', '2025-03-18 10:00:00'),
(2, 2, 2, '茶席套装的设计理念很好，莲花荷叶的图案与茶道文化非常契合。蓝白色调的深浅过渡需要更加细腻，建议多研究传统蓝印花布的层次表现技法。', 85, '2025-03-22 15:00:00', '2025-03-22 15:00:00'),
(3, 3, 3, '构图饱满，配色雅致，牡丹的花瓣层次感处理得很好。蝴蝶翅膀的渐变色可以再细腻一些，建议用套针技法来增强色彩过渡效果。整体水平在同期学员中表现突出。', 90, '2025-03-28 09:00:00', '2025-03-28 09:00:00'),
(4, 5, 4, '杯型规整，拉坯功底扎实。缠枝莲纹的绘制线条流畅，分水均匀。建议在口沿和足部的处理上再精细一些，这是判断瓷器品质的关键细节。', 86, '2025-04-03 14:00:00', '2025-04-03 14:00:00'),
(5, 1, 2, '二次查看后的补充点评：围巾的整体色牢度测试合格，洗涤后不褪色。建议下次注意浆料涂抹的均匀度，局部有轻微渗色。', 88, '2025-03-25 09:00:00', '2025-03-25 09:00:00');
INSERT INTO `growth_record` (`id`, `apprentice_id`, `record_type`, `title`, `description`, `related_id`, `related_type`, `created_at`) VALUES
