(7, 5, 'TASK_COMPLETE', '完成刻版学习任务', '完成了蓝印花布基础图案刻版学习任务，获得85分。', 1, 'TASK_SUBMISSION', '2025-03-03 10:00:00'),
(8, 6, 'TASK_COMPLETE', '完成刻版学习任务', '完成了蓝印花布基础图案刻版学习任务，获得88分。', 2, 'TASK_SUBMISSION', '2025-03-07 09:00:00'),
(9, 7, 'TASK_COMPLETE', '完成基础针法练习', '完成了苏绣基础针法练习任务，获得82分。', 3, 'TASK_SUBMISSION', '2025-03-12 11:00:00'),
(10, 8, 'TASK_COMPLETE', '完成基础针法练习', '完成了苏绣基础针法练习任务，获得90分的优秀成绩。', 4, 'TASK_SUBMISSION', '2025-03-10 14:00:00'),
(11, 9, 'TASK_COMPLETE', '完成拉坯基本功训练', '完成了景德镇传统拉坯基本功训练，获得80分。', 5, 'TASK_SUBMISSION', '2025-03-22 10:00:00'),
(12, 5, 'ARTWORK_SUBMIT', '提交作品：春归蓝印花布围巾', '完成并提交了第一件蓝印花布作品——春归蓝印花布围巾。', 1, 'ARTWORK', '2025-03-15 14:00:00'),
(13, 5, 'ARTWORK_REVIEWED', '作品获得师傅点评', '春归蓝印花布围巾获得张师傅点评，评分88分。', 1, 'ARTWORK', '2025-03-18 10:00:00'),
(14, 6, 'ARTWORK_SUBMIT', '提交作品：蓝印花布茶席套装', '完成并提交了蓝印花布茶席套装。', 2, 'ARTWORK', '2025-03-20 10:00:00'),
(15, 7, 'ARTWORK_SUBMIT', '提交作品：牡丹蝴蝶苏绣团扇', '完成并提交了第一幅苏绣作品——牡丹蝴蝶团扇。', 3, 'ARTWORK', '2025-03-25 11:00:00'),
(16, 7, 'ARTWORK_REVIEWED', '作品获得师傅点评', '牡丹蝴蝶苏绣团扇获得李师傅点评，评分90分，获得高度评价。', 3, 'ARTWORK', '2025-03-28 09:00:00'),
(17, 9, 'ARTWORK_SUBMIT', '提交作品：青花瓷茶杯组', '完成并提交了第一组青花瓷作品。', 5, 'ARTWORK', '2025-04-01 10:00:00'),
(18, 9, 'ARTWORK_REVIEWED', '作品获得师傅点评', '青花瓷茶杯组获得王师傅点评，评分86分。', 5, 'ARTWORK', '2025-04-03 14:00:00'),
(19, 5, 'COURSE_JOIN', '参加非遗文化公开讲座', '参加了由文化馆组织的非遗文化公开讲座活动。', 1, 'ACTIVITY', '2025-03-15 09:00:00'),
(20, 7, 'COURSE_JOIN', '参加苏绣艺术展览', '参加了苏州刺绣艺术展览活动。', 2, 'ACTIVITY', '2025-04-05 10:00:00');
INSERT INTO `activity` (`id`, `title`, `description`, `content`, `cover_url`, `location`, `start_time`, `end_time`, `max_participants`, `current_participants`, `heritage_project_id`, `status`, `publisher_id`, `created_at`, `updated_at`) VALUES
(1, '非遗文化公开讲座：蓝印花布的前世今生', '邀请国家级非遗传承人讲述蓝印花布的历史渊源、工艺特色与当代价值。', '本次讲座将从以下几个方面展开：\n1. 蓝印花布的历史沿革（明清至今）\n2. 传统印染工艺流程详解\n3. 蓝印花布图案的文化内涵\n4. 传统技艺的现代创新应用\n5. 互动问答与现场体验', NULL, '南通非遗展览馆报告厅', '2025-03-15 09:00:00', '2025-03-15 12:00:00', 50, 35, 1, 2, 1, '2025-02-28 10:00:00', '2025-03-15 12:00:00'),
(2, '苏绣艺术展览：针尖上的诗画', '展出苏州刺绣研究所及民间传承人的精品苏绣作品，含现场刺绣演示。', '展览内容包括：\n- 历代苏绣精品50余幅\n- 双面绣、乱针绣等技法演示\n- 苏绣与现代时尚的融合作品\n- 现场体验区（免费提供材料）', NULL, '苏州丝绸博物馆', '2025-04-05 10:00:00', '2025-04-10 17:00:00', 200, 86, 3, 1, 1, '2025-03-20 14:00:00', '2025-04-05 10:00:00'),
(3, '景德镇陶瓷文化研学营', '为期三天的景德镇陶瓷文化深度研学，体验从制泥到出窑的完整工序。', '研学行程：\nDay 1：参观古窑民俗博览区，了解千年制瓷历史\nDay 2：亲手体验拉坯、画坯，在传承人指导下完成作品\nDay 3：参观现代陶瓷工厂，了解传统与现代的结合', NULL, '江西景德镇古窑民俗博览区', '2025-05-01 08:00:00', '2025-05-03 18:00:00', 30, 12, 2, 0, 1, '2025-04-01 09:00:00', '2025-04-01 09:00:00'),
(4, '非遗技艺体验日：走进传统手工艺', '面向社会公众的非遗技艺体验活动，设置剪纸、蓝印花布、陶艺等多个体验区。', '活动设置以下体验区：\n1. 剪纸体验区 - 传承人现场教学\n2. 蓝印花布体验区 - 亲手制作蓝印花布作品\n3. 陶艺体验区 - 拉坯与绘制体验\n4. 刺绣体验区 - 基础针法学习\n每人可选择2个体验区参与', NULL, '市文化活动中心', '2025-04-20 09:00:00', '2025-04-20 17:00:00', 100, 45, NULL, 0, 1, '2025-04-05 10:00:00', '2025-04-05 10:00:00'),
(5, '非遗传承人座谈会', '邀请多位非遗传承人分享传承经验，探讨非遗保护与数字化发展方向。', '座谈主题：\n1. 师徒传承模式的现状与挑战\n2. 数字化技术在非遗保护中的应用\n3. 非遗产品的市场化探索\n4. 年轻一代传承人的培养路径', NULL, '文化馆三楼会议室', '2025-05-15 14:00:00', '2025-05-15 17:00:00', 40, 0, NULL, 0, 1, '2025-04-20 09:00:00', '2025-04-20 09:00:00'),
(6, '蓝印花布创意设计大赛', '面向所有学习蓝印花布技艺的徒弟，以"传统与创新"为主题的创意设计比赛。', '比赛规则：\n1. 参赛作品须以传统蓝印花布工艺制作\n2. 鼓励融入现代设计元素\n3. 作品需附创作说明\n4. 由专家评审团评选金银铜奖各1名', NULL, '线上提交 + 线下展览', '2025-06-01 00:00:00', '2025-06-30 23:59:59', 50, 0, 1, 0, 1, '2025-05-01 10:00:00', '2025-05-01 10:00:00');
